package dominoes

// Domino represents a domino tile with two values.
type Domino [2]int

// MakeChain attempts to form a valid chain from the given dominoes.
// This approach uses a recursive backtracking solver that tries to extend
// the chain by finding a domino that matches the current end.
func MakeChain(input []Domino) ([]Domino, bool) {
	n := len(input)
	if n == 0 {
		return []Domino{}, true
	}

	// We need to use all dominoes exactly once.
	// We'll track used dominoes by index.
	used := make([]bool, n)
	chain := make([]Domino, 0, n)

	// Start with the first domino in the input, trying both orientations.
	// We fix the first domino to avoid redundant permutations of the starting point.
	start := input[0]
	used[0] = true
	chain = append(chain, start)

	if solve(input, used, chain, n) {
		return chain, true
	}

	// Try flipping the first domino if it's not double
	if start[0] != start[1] {
		chain[0] = Domino{start[1], start[0]}
		if solve(input, used, chain, n) {
			return chain, true
		}
		chain[0] = start
	}

	return nil, false
}

func solve(input []Domino, used []bool, chain []Domino, n int) bool {
	if len(chain) == n {
		// Check if the chain closes the loop
		return chain[0][0] == chain[n-1][1]
	}

	lastVal := chain[len(chain)-1][1]

	for i := 1; i < n; i++ {
		if !used[i] {
			d := input[i]
			// Try to match d[0] with lastVal
			if d[0] == lastVal {
				used[i] = true
				chain = append(chain, d)
				if solve(input, used, chain, n) {
					return true
				}
				chain = chain[:len(chain)-1]
				used[i] = false
			}
			// Try to match d[1] with lastVal
			if d[1] == lastVal {
				// If d[0] == d[1], we already tried it above, so skip to avoid duplicate work
				if d[0] == d[1] {
					continue
				}
				used[i] = true
				chain = append(chain, Domino{d[1], d[0]})
				if solve(input, used, chain, n) {
					return true
				}
				chain = chain[:len(chain)-1]
				used[i] = false
			}
		}
	}

	return false
}

