std::vector<unsigned int> convert(int input_base, const std::vector<unsigned int>& digits, int output_base) {
    if (input_base < 2) {
        throw std::invalid_argument("input base must be >= 2");
    }
    if (output_base < 2) {
        throw std::invalid_argument("output base must be >= 2");
    }

    long long value = 0;
    for (unsigned int digit : digits) {
        if (digit >= static_cast<unsigned int>(input_base)) {
            throw std::invalid_argument("all digits must satisfy 0 <= d < input base");
        }
        value = value * input_base + digit;
    }

    if (value == 0) {
        return {};
    }

    std::vector<unsigned int> result;
    while (value > 0) {
        result.push_back(static_cast<unsigned int>(value % output_base));
        value /= output_base;
    }
    std::reverse(result.begin(), result.end());
    return result;
}

