public class SgfParsing {
    public SgfNode parse(String input) throws SgfParsingException {
        if (input == null || input.isEmpty()) {
            throw new SgfParsingException("tree missing");
        }

        if (!input.startsWith("(") || !input.endsWith(")")) {
            throw new SgfParsingException("tree missing");
        }

        String content = input.substring(1, input.length() - 1);
        if (content.isEmpty()) {
            throw new SgfParsingException("tree with no nodes");
        }

        if (!content.startsWith(";")) {
            throw new SgfParsingException("tree missing");
        }

        content = content.substring(1);
        if (content.isEmpty()) {
            throw new SgfParsingException("tree with no nodes");
        }

        return parseWithStack(content);
    }

    private SgfNode parseWithStack(String content) throws SgfParsingException {
        Map<String, List<String>> properties = new java.util.HashMap<>();
        int i = 0;

        while (i < content.length()) {
            char c = content.charAt(i);

            if (c == ';') {
                throw new SgfParsingException("tree with no nodes");
            }

            if (Character.isUpperCase(c)) {
                int start = i;
                while (i < content.length() && Character.isUpperCase(content.charAt(i))) {
                    i++;
                }
                String key = content.substring(start, i);

                if (i >= content.length() || content.charAt(i) != '[') {
                    throw new SgfParsingException("properties without delimiter");
                }

                i++; // skip '['
                StringBuilder value = new StringBuilder();
                while (i < content.length() && content.charAt(i) != ']') {
                    if (content.charAt(i) == '\\') {
                        i++;
                        if (i < content.length()) {
                            char next = content.charAt(i);
                            if (next == 'n') {
                                // escaped newline is converted to nothing
                            } else if (next == 't') {
                                // escaped tab is converted to nothing
                            } else if (next == 'r') {
                                // escaped carriage return is converted to nothing
                            } else {
                                value.append(next);
                            }
                            i++;
                        } else {
                            throw new SgfParsingException("properties without delimiter");
                        }
                    } else {
                        value.append(content.charAt(i));
                        i++;
                    }
                }

                if (i >= content.length() || content.charAt(i) != ']') {
                    throw new SgfParsingException("properties without delimiter");
                }
                i++; // skip ']'

                properties.put(key, java.util.List.of(value.toString()));
            } else {
                throw new SgfParsingException("property must be in uppercase");
            }
        }

        return new SgfNode(properties);
    }
}

export class Robot {
  constructor() {
    this._name = Robot.generateName();
  }

  get name() {
    return this._name;
  }

  reset() {
    this._name = Robot.generateName();
  }

  static generateName() {
    const letters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    const digits = '0123456789';
    let name;
    do {
      name = '';
      for (let i = 0; i < 2; i++) {
        name += letters.charAt(Math.floor(Math.random() * 26));
      }
      for (let i = 0; i < 3; i++) {
        name += digits.charAt(Math.floor(Math.random() * 10));
      }
    } while (Robot.usedNames.has(name));
    Robot.usedNames.add(name);
    return name;
  }

  static releaseNames() {
    Robot.usedNames.clear();
  }

  static usedNames = new Set();
}

pub enum Error {
    IncompleteNumber,
}

pub fn to_bytes(values: &[u32]) -> Vec<u8> {
    values.iter().flat_map(|&v| {
        if v == 0 {
            return vec![0x00];
        }
        let mut v = v;
        let mut bytes = Vec::new();
        while v > 0 {
            bytes.push((v & 0x7f) as u8);
            v >>= 7;
        }
        bytes.reverse();
        let len = bytes.len();
        for i in 0..len {
            if i < len - 1 {
                bytes[i] |= 0x80;
            }
        }
        bytes
    }).collect()
}

pub fn from_bytes(bytes: &[u8]) -> Result<Vec<u32>, Error> {
    let mut result = Vec::new();
    let mut current: u32 = 0;
    let mut incomplete = false;

    for &byte in bytes {
        current = (current << 7) | (byte & 0x7f) as u32;
        if byte & 0x80 == 0 {
            result.push(current);
            current = 0;
            incomplete = false;
        } else {
            incomplete = true;
        }
    }

    if incomplete {
        return Err(Error::IncompleteNumber);
    }

    Ok(result)
}

def recite(start, take=1):
    def format_bottle(n):
        if n == 0:
            return "no more bottles"
        elif n == 1:
            return "1 bottle"
        else:
            return f"{n} bottles"

    def generate_verse(n):
        if n == 0:
            return [
                "No more bottles of beer on the wall, no more bottles of beer.",
                "Go to the store and buy some more, 99 bottles of beer on the wall."
            ]
        elif n == 1:
            return [
                "1 bottle of beer on the wall, 1 bottle of beer.",
                "Take it down and pass it around, no more bottles of beer on the wall."
            ]
        else:
            current = format_bottle(n)
            next_val = format_bottle(n - 1)
            action = "Take it down" if n == 1 else "Take one down"
            return [
                f"{current} of beer on the wall, {current} of beer.",
                f"{action} and pass it around, {next_val} of beer on the wall."
            ]

    verses = []
    for i in range(take):
        verse = generate_verse(start - i)
        verses.extend(verse)
        if i < take - 1:
            verses.append("")
    return verses

