export const recite = (initialBottlesCount, takeDownCount) => {
  const numWords = ['no', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight', 'nine', 'ten'];

  const getWord = (n) => numWords[n];
  const getSingularPlural = (n) => n === 1 ? 'bottle' : 'bottles';
  const toTitleCase = (s) => s.charAt(0).toUpperCase() + s.slice(1);

  const verse = (n) => {
    const currentWord = toTitleCase(getWord(n));
    const currentBottle = getSingularPlural(n);
    const nextCount = n - 1;
    const nextWord = getWord(nextCount);
    const nextBottle = getSingularPlural(nextCount);

    return [
      `${currentWord} green ${currentBottle} hanging on the wall,`,
      `${currentWord} green ${currentBottle} hanging on the wall,`,
      'And if one green bottle should accidentally fall,',
      `There'll be ${nextWord} green ${nextBottle} hanging on the wall.`
    ];
  };

  const result = [];
  for (let i = 0; i < takeDownCount; i++) {
    const start = initialBottlesCount - i;
    result.push(...verse(start));
    if (i < takeDownCount - 1) {
      result.push('');
    }
  }

  return result;
};

