pub enum Error {
    NotEnoughPinsLeft,
    GameComplete,
}

pub struct BowlingGame {
    rolls: Vec<u16>,
}

impl BowlingGame {
    pub fn new() -> Self {
        BowlingGame { rolls: Vec::new() }
    }

    pub fn roll(&mut self, pins: u16) -> Result<(), Error> {
        if self.is_game_complete() {
            return Err(Error::GameComplete);
        }

        if pins > 10 {
            return Err(Error::NotEnoughPinsLeft);
        }

        if !self.can_roll(pins) {
            return Err(Error::NotEnoughPinsLeft);
        }

        self.rolls.push(pins);
        Ok(())
    }

    pub fn score(&self) -> Option<u16> {
        if !self.is_game_complete() {
            return None;
        }

        let mut score = 0;
        let mut roll_index = 0;

        for _ in 0..10 {
            if self.rolls[roll_index] == 10 {
                // Strike
                score += 10 + self.rolls[roll_index + 1] + self.rolls[roll_index + 2];
                roll_index += 1;
            } else if self.rolls[roll_index] + self.rolls[roll_index + 1] == 10 {
                // Spare
                score += 10 + self.rolls[roll_index + 2];
                roll_index += 2;
            } else {
                // Open frame
                score += self.rolls[roll_index] + self.rolls[roll_index + 1];
                roll_index += 2;
            }
        }

        Some(score)
    }

    fn is_game_complete(&self) -> bool {
        if self.rolls.is_empty() {
            return false;
        }

        let mut roll_index = 0;
        let mut frame = 0;

        while frame < 9 {
            if self.rolls[roll_index] == 10 {
                roll_index += 1;
            } else {
                roll_index += 2;
            }
            frame += 1;
        }

        // Frame 10
        if roll_index >= self.rolls.len() {
            return false;
        }

        if self.rolls[roll_index] == 10 {
            if roll_index + 2 >= self.rolls.len() {
                return false;
            }
            if self.rolls[roll_index + 1] < 10 {
                if roll_index + 3 >= self.rolls.len() {
                    return false;
