                // Second roll of frame 10
                if self.rolls[roll_index] + self.rolls[roll_index + 1] == 10 {
                    // Spare, third roll can be anything up to 10
                    return pins <= 10;
                } else {
                    // Open frame, shouldn't get here
                    return false;
                }
            }
        }
    }
}

export class QueenAttack {
  constructor({
    black: [blackRow, blackColumn] = [],
    white: [whiteRow, whiteColumn] = [],
  } = {}) {
    const validatePosition = (row, col, name) => {
      if (row < 0 || row > 7 || col < 0 || col > 7) {
        throw new Error('Queen must be placed on the board');
      }
    };

    validatePosition(whiteRow, whiteColumn, 'white');
    validatePosition(blackRow, blackColumn, 'black');

    if (whiteRow === blackRow && whiteColumn === blackColumn) {
      throw new Error('Queens cannot share the same space');
    }

    this.white = [whiteRow, whiteColumn];
    this.black = [blackRow, blackColumn];
  }

  toString() {
    const rows = [];
    for (let r = 0; r < 8; r++) {
      let rowStr = '';
      for (let c = 0; c < 8; c++) {
        if (r === this.white[0] && c === this.white[1]) {
          rowStr += 'W';
        } else if (r === this.black[0] && c === this.black[1]) {
          rowStr += 'B';
        } else {
          rowStr += '.';
        }
        if (c < 7) rowStr += ' ';
      }
      rows.push(rowStr);
    }
    return rows.join('\n');
  }

  get canAttack() {
    const [wRow, wCol] = this.white;
    const [bRow, bCol] = this.black;

    const sameRow = wRow === bRow;
    const sameCol = wCol === bCol;
    const sameDiag = Math.abs(wRow - bRow) === Math.abs(wCol - bCol);

    return sameRow || sameCol || sameDiag;
  }
}

pub fn answer(command: &str) -> Option<i32> {
    let s = command.trim();
    if !s.starts_with("What is ") || !s.ends_with('?') {
        return None;
    }

    let mut tokens = s[8..s.len()-1].split_whitespace();

    let mut result: i32 = tokens.next()?.parse().ok()?;

    loop {
        let op = tokens.next()?;

        match op {
            "plus" => {
                let val = tokens.next()?.parse::<i32>().ok()?;
                result = result.wrapping_add(val);
            },
            "minus" => {
                let val = tokens.next()?.parse::<i32>().ok()?;
                result = result.wrapping_sub(val);
            },
            "multiplied" => {
                if tokens.next() != Some("by") {
                    return None;
                }
                let val = tokens.next()?.parse::<i32>().ok()?;
                result = result.wrapping_mul(val);
            },
            "divided" => {
                if tokens.next() != Some("by") {
                    return None;
                }
                let val = tokens.next()?.parse::<i32>().ok()?;
                if val == 0 {
                    return None;
                }
                result = result.wrapping_div(val);
            },
            _ => return None,
        }
    }
}

NODE, EDGE, ATTR = range(3)


class Node:
    def __init__(self, name, attrs):
        self.name = name
        self.attrs = attrs

    def __eq__(self, other):
        return self.name == other.name and self.attrs == other.attrs


class Edge:
    def __init__(self, src, dst, attrs):
        self.src = src
        self.dst = dst
        self.attrs = attrs

    def __eq__(self, other):
        return (self.src == other.src and
                self.dst == other.dst and
                self.attrs == other.attrs)


class Graph:
    def __init__(self, data=None):
        self.nodes = []
        self.edges = []
        self.attrs = {}

        if data is None:
            return

        if not isinstance(data, list):
            raise TypeError("Graph data malformed")

        for item in data:
            if not isinstance(item, tuple) or len(item) == 0:
                raise TypeError("Graph item incomplete")

            try:
                if item[0] == ATTR:
                    if len(item) != 3:
                        raise TypeError("Graph item incomplete")
                    key, value = item[1], item[2]
                    if not isinstance(key, str) or not isinstance(value, str):
                        raise TypeError("Graph item incomplete")
                    self.attrs[key] = value

                elif item[0] == NODE:
                    if len(item) != 3:
                        raise TypeError("Graph item incomplete")
                    name, attrs = item[1], item[2]
                    if not isinstance(name, str) or not isinstance(attrs, dict):
                        raise TypeError("Graph item incomplete")
                    self.nodes.append(Node(name, attrs))

                elif item[0] == EDGE:
                    if len(item) != 4:
                        raise TypeError("Graph item incomplete")
                    src, dst, attrs = item[1], item[2], item[3]
                    if not isinstance(src, str) or not isinstance(dst, str) or not isinstance(attrs, dict):
                        raise TypeError("Graph item incomplete")
                    self.edges.append(Edge(src, dst, attrs))

                else:
                    raise TypeError("Graph data malformed")
            except (IndexError, TypeError):
                raise TypeError("Graph item incomplete")

import java.util.*;

class Satellite {
    public Tree treeFromTraversals(List<Character> preorder, List<Character> inorder) {
        if (preorder.size() != inorder.size()) {
            throw new IllegalArgumentException("traversals must have the same length");
        }

        if (!preorder.isEmpty()) {
            if (!preorder.containsAll(inorder) || !inorder.containsAll(preorder)) {
                throw new IllegalArgumentException("traversals must have the same elements");
            }
            if (preorder.size() != preorder.stream().distinct().count()) {
                throw new IllegalArgumentException("traversals must contain unique elements");
            }
        }

        if (preorder.isEmpty()) {
            return new Tree(List.of(), List.of(), List.of());
        }

        Map<Character, Integer> inorderIndexMap = new HashMap<>();
        for (int i = 0; i < inorder.size(); i++) {
            inorderIndexMap.put(inorder.get(i), i);
        }

        Node root = buildTreeWithIndices(preorder, 0, preorder.size() - 1, 
                                        inorder, 0, inorder.size() - 1, inorderIndexMap);

        List<Character> pre = new ArrayList<>();
        List<Character> in = new ArrayList<>();
        List<Character> post = new ArrayList<>();
        collectTraversals(root, pre, in, post);

        return new Tree(pre, in, post);
    }

    private Node buildTreeWithIndices(List<Character> preorder, int preStart, int preEnd, 
                                     List<Character> inorder, int inStart, int inEnd, 
                                     Map<Character, Integer> inorderIndexMap) {
        if (preStart > preEnd || inStart > inEnd) {
            return null;
        }

        char rootValue = preorder.get(preStart);
        Node root = new Node(rootValue);

        int inRootIndex = inorderIndexMap.get(rootValue);
        int leftSubtreeSize = inRootIndex - inStart;

        root.left = buildTreeWithIndices(preorder, preStart + 1, preStart + leftSubtreeSize, 
                                        inorder, inStart, inRootIndex - 1, inorderIndexMap);
        root.right = buildTreeWithIndices(preorder, preStart + leftSubtreeSize + 1, preEnd, 
                                         inorder, inRootIndex + 1, inEnd, inorderIndexMap);

        return root;
    }

    private void collectTraversals(Node node, List<Character> pre, List<Character> in, List<Character> post) {
        if (node == null) return;

        pre.add(node.value);
        collectTraversals(node.left, pre, in, post);
        in.add(node.value);
        collectTraversals(node.right, pre, in, post);
        post.add(node.value);
    }
}

class Tree {
    private final List<Character> preorder;
    private final List<Character> inorder;
    private final List<Character> postorder;

    public Tree(List<Character> preorder, List<Character> inorder, List<Character> postorder) {
        this.preorder = preorder;
        this.inorder = inorder;
        this.postorder = postorder;
    }

    public List<Character> preorder() {
        return preorder;
    }

    public List<Character> inorder() {
        return inorder;
    }

    public List<Character> postorder() {
        return postorder;
    }
}

class Node {
    public final char value;
    public Node left;
    public Node right;

    public Node(char value) {
        this(value, null, null);
    }

    Node(char value, Node left, Node right) {
        this.value = value;
        this.left = left;
        this.right = right;
    }
}

#include "diamond.h"
