namespace diamond {

std::vector<std::string> rows(char letter) {
    if (letter < 'A' || letter > 'Z') {
        return {};
    }

    int n = letter - 'A';
    int size = 2 * n + 1;
    std::vector<std::string> result;

    // Create the full diamond using a single loop with symmetry
    for (int i = 0; i < size; ++i) {
        // Calculate the row index in the top half (0 to n)
        int rowIdx = (i <= n) ? i : (size - 1 - i);
        char currentChar = 'A' + rowIdx;

        std::string row(size, ' ');

        if (rowIdx == 0) {
            row[n] = currentChar;
        } else {
            row[n - rowIdx] = currentChar;
            row[n + rowIdx] = currentChar;
        }

        result.push_back(row);
    }

    return result;
}

}  // namespace diamond

pub fn map<I, O, F>(input: Vec<I>, mut function: F) -> Vec<O>
where
    F: FnMut(I) -> O,
{
    let mut result = Vec::with_capacity(input.len());
    for item in input {
        result.push(function(item));
    }
    result
}

package erratum

// Resource is an interface representing a resource that can be frobbed, defrobed, and closed.
type Resource interface {
	Frob(string)
	Defrob(string)
	Close() error
}

// ResourceOpener is a function type that opens a resource.
type ResourceOpener func() (Resource, error)

// TransientError is an error that indicates a transient failure.
type TransientError struct {
	err error
}

func (e TransientError) Error() string {
	return e.err.Error()
}

// FrobError is an error that occurs during Frob.
type FrobError struct {
	sub string
	err error
}

func (e FrobError) Error() string {
	return e.err.Error()
}

// Use opens a resource, frobs it, and ensures it is closed.
// It handles transient errors by retrying, and handles panics by defrobing and closing.
func Use(opener ResourceOpener, input string) error {
	var r Resource
	var err error

	for {
		r, err = opener()
		if err == nil {
			break
		}
		if _, ok := err.(TransientError); !ok {
			return err
		}
	}

	defer func() {
		if rec := recover(); rec != nil {
			var tag string
			var innerErr error
			if fe, ok := rec.(FrobError); ok {
				tag = fe.sub
				innerErr = fe.err
			} else {
				r.Close()
				panic(rec)
			}
			r.Defrob(tag)
			r.Close()
			panic(innerErr)
		}
	}()

	r.Frob(input)
	r.Close()
	return nil
}

