public class Ledger {
    public LedgerEntry createLedgerEntry(String d, String desc, int c) {
        LedgerEntry le = new LedgerEntry();
        le.setChange(c);
        le.setDescription(desc);
        le.setLocalDate(LocalDate.parse(d));
        return le;
    }

    public String format(String cur, String loc, LedgerEntry[] entries) {
        if (!cur.equals("USD") && !cur.equals("EUR")) {
            throw new IllegalArgumentException("Invalid currency");
        }
        if (!loc.equals("en-US") && !loc.equals("nl-NL")) {
            throw new IllegalArgumentException("Invalid locale");
        }

        String header;
        String datePattern;
        String decimalSeparator;
        String thousandsSeparator;
        String currencySymbol;
        String localeName;

        if (loc.equals("en-US")) {
            header = "Date       | Description               | Change       ";
            datePattern = "MM/dd/yyyy";
            decimalSeparator = ".";
            thousandsSeparator = ",";
            currencySymbol = cur.equals("USD") ? "$" : "€";
            localeName = "en-US";
        } else {
            header = "Datum      | Omschrijving              | Verandering  ";
            datePattern = "dd/MM/yyyy";
            decimalSeparator = ",";
            thousandsSeparator = ".";
            currencySymbol = cur.equals("USD") ? "$" : "€";
            localeName = "nl-NL";
        }

        List<LedgerEntry> sortedEntries = new ArrayList<>(Arrays.asList(entries));
        sortedEntries.sort(Comparator
            .comparing(LedgerEntry::getLocalDate)
            .thenComparing(LedgerEntry::getDescription)
            .thenComparing(LedgerEntry::getChange));

        StringBuilder sb = new StringBuilder();
        sb.append(header);

        for (LedgerEntry entry : sortedEntries) {
            String dateStr = entry.getLocalDate().format(DateTimeFormatter.ofPattern(datePattern));
            String desc = entry.getDescription();
            if (desc.length() > 25) {
                desc = desc.substring(0, 22) + "...";
            }

            double amountInDollars = entry.getChange() / 100.0;
            String formattedAmount = formatAmount(amountInDollars, currencySymbol, localeName, decimalSeparator, thousandsSeparator);

            sb.append("\n");
            sb.append(String.format("%s | %-25s | %13s", dateStr, desc, formattedAmount));
        }

        return sb.toString();
    }

    private String formatAmount(double amount, String currencySymbol, String localeName, String decimalSeparator, String thousandsSeparator) {
        boolean isNegative = amount < 0;
        double absAmount = Math.abs(amount);

        String[] parts = String.format(Locale.US, "%.2f", absAmount).split("\\.");
        String integerPart = parts[0];
        String decimalPart = parts[1];

        StringBuilder sb = new StringBuilder();
        int count = 0;
        for (int i = integerPart.length() - 1; i >= 0; i--) {
            if (count > 0 && count % 3 == 0) {
                sb.insert(0, thousandsSeparator);
            }
            sb.insert(0, integerPart.charAt(i));
            count++;
        }
        integerPart = sb.toString();

        String result = currencySymbol + integerPart + decimalSeparator + decimalPart;

        if (isNegative) {
            if (localeName.equals("en-US")) {
                return "(" + result + ")";
            } else {
                return currencySymbol + " -" + integerPart + decimalSeparator + decimalPart + " ";
            }
        } else {
            if (localeName.equals("nl-NL")) {
                return " " + result + " ";
            } else {
                return result + " ";
            }
        }
    }

    public static class LedgerEntry {
        LocalDate localDate;
        String description;
        double change;

        public LocalDate getLocalDate() {
            return localDate;
        }

        public void setLocalDate(LocalDate localDate) {
            this.localDate = localDate;
        }

        public String getDescription() {
            return description;
        }

        public void setDescription(String description) {
            this.description = description;
        }

        public double getChange() {
            return change;
        }

        public void setChange(double change) {
            this.change = change;
        }
    }
}

