import (
	"errors"
)

func ResultOf(lines []string) (string, error) {
	if len(lines) == 0 {
		return "", nil
	}

	// Clean and validate board
	board := make([][]rune, len(lines))
	for i, line := range lines {
		cleaned := make([]rune, 0, len(line))
		for _, r := range line {
			if r != ' ' {
				cleaned = append(cleaned, r)
			}
		}
		if len(cleaned) == 0 {
			return "", errors.New("invalid board row")
		}
		board[i] = cleaned
	}

	// Check X (Left -> Right)
	if canConnect(board, 'X', func(r, c int) bool { return c == len(board[0])-1 }, func(r, c int) bool { return c == 0 }) {
		return "X", nil
	}

	// Check O (Top -> Bottom)
	if canConnect(board, 'O', func(r, c int) bool { return r == len(board)-1 }, func(r, c int) bool { return r == 0 }) {
		return "O", nil
	}

	return "", nil
}

func canConnect(board [][]rune, player rune, isWin func(r, c int) bool, isStart func(r, c int) bool) bool {
	rows := len(board)
	cols := len(board[0])
	visited := make([][]bool, rows)
	for i := range visited {
		visited[i] = make([]bool, cols)
	}

	// Stack for DFS
	type pos struct{ r, c int }
	stack := []pos{}

	// Push all starting positions
	for r := 0; r < rows; r++ {
		for c := 0; c < cols; c++ {
			if board[r][c] == player && isStart(r, c) {
				stack = append(stack, pos{r, c})
				visited[r][c] = true
			}
		}
	}

	// Hex neighbors offsets
	neighbors := [][2]int{
		{-1, 0}, {-1, 1},
		{0, -1}, {0, 1},
		{1, -1}, {1, 0},
	}

	for len(stack) > 0 {
		curr := stack[len(stack)-1]
		stack = stack[:len(stack)-1]
		r, c := curr.r, curr.c

		if isWin(r, c) {
			return true
		}

		for _, n := range neighbors {
			nr, nc := r+n[0], c+n[1]
			if nr >= 0 && nr < rows && nc >= 0 && nc < cols {
				if !visited[nr][nc] && board[nr][nc] == player {
					visited[nr][nc] = true
					stack = append(stack, pos{nr, nc})
				}
			}
		}
	}

	return false
}

