import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Stack;
import java.util.regex.Pattern;

class ForthEvaluator {
    private static final Pattern NUMBER_PATTERN = Pattern.compile("^-?\\d+$");
    private Map<String, List<String>> customWords = new HashMap<>();

    public List<Integer> evaluateProgram(List<String> input) {
        customWords = new HashMap<>();
        List<Integer> stack = new ArrayList<>();

        for (String line : input) {
            List<String> tokens = new ArrayList<>();
            String[] parts = line.trim().split("\\s+");
            for (String part : parts) {
                if (!part.isEmpty()) {
                    tokens.add(part);
                }
            }
            processTokens(tokens, stack);
        }
        return stack;
    }

    private void processTokens(List<String> tokens, List<Integer> stack) {
        int i = 0;
        while (i < tokens.size()) {
            String token = tokens.get(i).toUpperCase();

            if (token.equals(":")) {
                i++;
                if (i >= tokens.size()) {
                    throw new IllegalArgumentException("Invalid definition");
                }
                String wordName = tokens.get(i).toUpperCase();
                if (NUMBER_PATTERN.matcher(wordName).matches()) {
                    throw new IllegalArgumentException("Invalid definition");
                }
                i++;
                List<String> definition = new ArrayList<>();
                while (i < tokens.size() && !tokens.get(i).equals(";")) {
                    definition.add(tokens.get(i).toUpperCase());
                    i++;
                }
                if (i >= tokens.size()) {
                    throw new IllegalArgumentException("Invalid definition");
                }
                customWords.put(wordName, definition);
                i++;
            } else {
                executeToken(token, stack);
                i++;
            }
        }
    }

    private void executeToken(String token, List<Integer> stack) {
        if (NUMBER_PATTERN.matcher(token).matches()) {
            stack.add(Integer.parseInt(token));
            return;
        }

        if (customWords.containsKey(token)) {
            List<String> definition = customWords.get(token);
            for (String defToken : definition) {
                executeToken(defToken, stack);
            }
            return;
        }

        switch (token) {
            case "+":
                if (stack.size() < 2) throw new IllegalArgumentException("Addition requires that the stack contain at least 2 values");
                int b = stack.remove(stack.size() - 1);
                int a = stack.remove(stack.size() - 1);
                stack.add(a + b);
                break;
            case "-":
                if (stack.size() < 2) throw new IllegalArgumentException("Subtraction requires that the stack contain at least 2 values");
                b = stack.remove(stack.size() - 1);
                a = stack.remove(stack.size() - 1);
                stack.add(a - b);
                break;
            case "*":
                if (stack.size() < 2) throw new IllegalArgumentException("Multiplication requires that the stack contain at least 2 values");
                b = stack.remove(stack.size() - 1);
                a = stack.remove(stack.size() - 1);
                stack.add(a * b);
                break;
            case "/":
                if (stack.size() < 2) throw new IllegalArgumentException("Division requires that the stack contain at least 2 values");
                b = stack.remove(stack.size() - 1);
                a = stack.remove(stack.size() - 1);
                if (b == 0) throw new IllegalArgumentException("Division by zero");
                stack.add(a / b);
                break;
            case "DUP":
                if (stack.size() < 1) throw new IllegalArgumentException("DUP requires that the stack contain at least 1 value");
                stack.add(stack.get(stack.size() - 1));
                break;
            case "DROP":
                if (stack.size() < 1) throw new IllegalArgumentException("DROP requires that the stack contain at least 1 value");
                stack.remove(stack.size() - 1);
                break;
            case "SWAP":
                if (stack.size() < 2) throw new IllegalArgumentException("SWAP requires that the stack contain at least 2 values");
                int top = stack.remove(stack.size() - 1);
                int second = stack.remove(stack.size() - 1);
                stack.add(top);
                stack.add(second);
                break;
            case "OVER":
                if (stack.size() < 2) throw new IllegalArgumentException("OVER requires that the stack contain at least 2 values");
                stack.add(stack.get(stack.size() - 2));
                break;
            default:
                throw new IllegalArgumentException("Unknown word");
        }
    }
}

def can_chain(dominoes):
    if not dominoes:
        return []

    n = len(dominoes)
    used = [False] * n
    chain = []

    def solve():
        if len(chain) == n:
            return chain[0][0] == chain[-1][1]

        if not chain:
            for i in range(n):
                if not used[i]:
                    used[i] = True
                    chain.append(dominoes[i])
                    if solve():
                        return True
                    chain.pop()
                    used[i] = False

                    if dominoes[i][0] != dominoes[i][1]:
                        chain.append((dominoes[i][1], dominoes[i][0]))
                        if solve():
                            return True
                        chain.pop()
                    used[i] = False
            return False

        target = chain[-1][1]
        for i in range(n):
            if not used[i]:
                d = dominoes[i]
                if d[0] == target:
                    used[i] = True
                    chain.append(d)
                    if solve():
                        return True
                    chain.pop()
                    used[i] = False
                elif d[1] == target:
                    used[i] = True
                    chain.append((d[1], d[0]))
                    if solve():
                        return True
                    chain.pop()
                    used[i] = False
        return False

    if solve():
        return chain
    return None

package wordsearch

import "errors"

func Solve(words []string, puzzle []string) (map[string][2][2]int, error) {
	if len(puzzle) == 0 {
		return nil, errors.New("empty puzzle")
	}
	rows := len(puzzle)
	cols := len(puzzle[0])
	for _, row := range puzzle {
		if len(row) != cols {
			return nil, errors.New("puzzle rows have different lengths")
		}
	}

	results := make(map[string][2][2]int)
	// Directions: right, left, down, up, down-right, down-left, up-right, up-left
	dr := []int{0, 0, 1, -1, 1, 1, -1, -1}
	dc := []int{1, -1, 0, 0, 1, -1, 1, -1}

	for _, word := range words {
		if len(word) == 0 {
			continue
		}
		found := false
		for r := 0; r < rows; r++ {
			for c := 0; c < cols; c++ {
				if puzzle[r][c] != word[0] {
					continue
				}
				for d := 0; d < 8; d++ {
					endR, endC, ok := checkDirection(puzzle, word, r, c, dr[d], dc[d], rows, cols)
					if ok {
						results[word] = [2][2]int{{r, c}, {endR, endC}}
						found = true
						break
					}
				}
				if found {
					break
				}
			}
			if found {
				break
			}
		}
		if !found {
			return nil, errors.New("word not found: " + word)
		}
	}
	return results, nil
}

func checkDirection(puzzle []string, word string, startR, startC, dr, dc, rows, cols int) (int, int, bool) {
	r, c := startR, startC
	for i := 0; i < len(word); i++ {
		if r < 0 || r >= rows || c < 0 || c >= cols {
			return 0, 0, false
		}
		if puzzle[r][c] != word[i] {
			return 0, 0, false
		}
		r += dr
		c += dc
	}
	return r - dr, c - dc, true
}

export class Element {
  constructor(value, next = null) {
    this.value = value;
    this.next = next;
  }
}

export class List {
  constructor(values = []) {
    this._head = null;
    this._length = 0;
    if (Array.isArray(values)) {
      for (const val of values) {
        this.add(new Element(val));
      }
    }
  }

  add(nextValue) {
    nextValue.next = this._head;
    this._head = nextValue;
    this._length++;
  }

  get length() {
    return this._length;
  }

  get head() {
    return this._head;
  }

  toArray() {
    const arr = [];
    let node = this._head;
    while (node !== null) {
      arr.push(node.value);
      node = node.next;
    }
    return arr;
  }

  reverse() {
    let prev = null;
    let curr = this._head;
    while (curr !== null) {
      const nextTemp = curr.next;
      curr.next = prev;
      prev = curr;
      curr = nextTemp;
    }
    this._head = prev;
    return this;
  }
}

package counter

import (
	"testing"
)

type Counter struct {
	lines, letters, characters int
}

func New() *Counter {
	return &Counter{}
}

func (c *Counter) Add(s string) {
	c.lines += 0
	c.letters = 0
	c.characters = 0
	for i := 0; i < len(s); i++ {
		c.characters++
		if s[i] == '\n' {
			c.lines++
		} else if s[i] != ' ' && s[i] != '\t' && s[i] != '\r' {
			c.letters++
		}
	}
}

func (c *Counter) Lines() int {
	return c.lines
}

func (c *Counter) Letters() int {
	return c.letters
}

func (c *Counter) Characters() int {
	return c.characters
}

func TestCounter(t *testing.T) {
	tests := []struct {
		name     string
		inputs   []string
		wantLines int
		wantLetters int
		wantChars int
	}{
		{
			name:     "empty input",
			inputs:   []string{},
			wantLines: 0,
			wantLetters: 0,
			wantChars: 0,
		},
		{
			name:     "single line",
			inputs:   []string{"hello"},
			wantLines: 0,
			wantLetters: 5,
			wantChars: 5,
		},
		{
			name:     "multiple lines",
			inputs:   []string{"hello\nworld"},
			wantLines: 1,
			wantLetters: 10,
			wantChars: 11,
		},
		{
			name:     "with spaces and tabs",
			inputs:   []string{"a b\tc"},
			wantLines: 0,
			wantLetters: 3,
			wantChars: 5,
		},
		{
			name:     "multiple adds",
			inputs:   []string{"a", "b\n", "c"},
			wantLines: 1,
			wantLetters: 3,
			wantChars: 5,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			c := New()
			for _, s := range tt.inputs {
				c.Add(s)
			}
			if got := c.Lines(); got != tt.wantLines {
				t.Errorf("Lines() = %d, want %d", got, tt.wantLines)
			}
			if got := c.Letters(); got != tt.wantLetters {
				t.Errorf("Letters() = %d, want %d", got, tt.wantLetters)
			}
			if got := c.Characters(); got != tt.wantChars {
				t.Errorf("Characters() = %d, want %d", got, tt.wantChars)
			}
		})
	}
}

import java.util.ArrayList;
import java.util.List;
import java.util.function.Consumer;
import java.util.function.Function;
import java.util.Set;
import java.util.HashSet;

public class React {

    public static class Cell<T> {
        protected T value;
        protected List<ComputeCell<T>> dependents = new ArrayList<>();

        public T getValue() {
            return value;
        }
    }

    public static class InputCell<T> extends Cell<T> {
        public InputCell(T initialValue) {
            this.value = initialValue;
        }

        public void setValue(T newValue) {
            if (this.value.equals(newValue)) {
                return;
            }
            this.value = newValue;
            propagateChanges();
        }

        private void propagateChanges() {
            List<ComputeCell<T>> toUpdate = new ArrayList<>();
            for (ComputeCell<T> dep : dependents) {
                if (!dep.isMarked()) {
                    dep.mark();
                    toUpdate.add(dep);
                }
            }
            // Sort by dependency depth implicitly by re-traversing if needed, 
            // but since we mark and only update marked, we need a topological order or iterative pass.
            // For simplicity in this approach, we do a recursive update that ensures stability.
            updateAll(toUpdate);
        }

        private void updateAll(List<ComputeCell<T>> list) {
            // We need to ensure we process in an order where dependencies are updated first.
            // Since we marked them, we can just iterate until no changes occur or use a queue.
            // A simpler way for this specific problem structure:
            // Just iterate the dependents. If a dependent's inputs changed, it updates.
            // But we need to handle chains.
            // Let's use a set to track visited to avoid cycles (though DAG is expected) and process.
            Set<ComputeCell<T>> processed = new HashSet<>();
            for (ComputeCell<T> cell : list) {
                if (!processed.contains(cell)) {
                    cell.update();
                    processed.add(cell);
                }
            }
        }
    }

    public static class ComputeCell<T> extends Cell<T> {
        private final Function<List<T>, T> function;
        private final List<Cell<T>> inputs;
        private final List<Consumer<T>> callbacks = new ArrayList<>();
        private T previousValue;
        private boolean marked = false;

        public ComputeCell(Function<List<T>, T> function, List<Cell<T>> inputs) {
            this.function = function;
            this.inputs = inputs;
            this.value = computeValue();
            this.previousValue = this.value;
            for (Cell<T> input : inputs) {
                input.dependents.add(this);
            }
        }

        private T computeValue() {
            List<T> inputValues = new ArrayList<>();
            for (Cell<T> cell : inputs) {
                inputValues.add(cell.getValue());
            }
            return function.apply(inputValues);
        }

        public boolean isMarked() {
            return marked;
        }

        public void mark() {
            this.marked = true;
        }

        public void update() {
            if (!marked) return;
            T newValue = computeValue();
            if (!newValue.equals(this.value)) {
                this.value = newValue;
                for (Consumer<T> callback : callbacks) {
                    callback.accept(newValue);
                }
            }
            this.marked = false;
        }

        public void addCallback(Consumer<T> callback) {
            callbacks.add(callback);
        }

        public void removeCallback(Consumer<T> callback) {
            callbacks.remove(callback);
        }
    }

    public static <T> InputCell<T> inputCell(T initialValue) {
        return new InputCell<>(initialValue);
    }

    public static <T> ComputeCell<T> computeCell(Function<List<T>, T> function, List<Cell<T>> cells) {
        return new ComputeCell<>(function, cells);
    }
}

export const convert = (input) => {
  if (!input) return '';

  const lines = input.split('\n');

  if (lines.length % 4 !== 0) {
    throw new Error('Number of input lines is not a multiple of four');
  }

  const width = lines[0].length;
  if (width % 3 !== 0) {
    throw new Error('Number of input columns is not a multiple of three');
  }

  for (let i = 0; i < lines.length; i++) {
    if (lines[i].length !== width) {
      throw new Error('Number of input columns is not a multiple of three');
    }
  }

  const digitPatterns = {
    ' _ | ||_|   ': '0',
    '     |  |   ': '1',
    ' _  _||_    ': '2',
    ' _  _| _|   ': '3',
    '   |_|  |   ': '4',
    ' _ |_  _|   ': '5',
    ' _ |_ |_|   ': '6',
    ' _   |  |   ': '7',
    ' _ |_||_|   ': '8',
    ' _ |_| _|   ': '9'
  };

  const numDigits = width / 3;
  const numGroups = lines.length / 4;
  let result = '';

  for (let group = 0; group < numGroups; group++) {
    const groupStart = group * 4;
    for (let digit = 0; digit < numDigits; digit++) {
      let pattern = '';
      for (let row = 0; row < 4; row++) {
        const lineIndex = groupStart + row;
        const colStart = digit * 3;
        pattern += lines[lineIndex].substring(colStart, colStart + 3);
      }
      result += digitPatterns[pattern] || '?';
    }
    if (group < numGroups - 1) {
      result += ',';
    }
  }

  return result;
};

class Scale:
    def __init__(self, tonic):
        self.tonic = tonic
        self._setup_scale()

    def _setup_scale(self):
        tonic_lower = self.tonic.lower()

        # Determine if we use sharps or flats based on the tonic
        # Sharps: C, G, D, A, E, B, F#, e, b, f#, c#, g#, d#, a
        # Flats: F, Bb, Eb, Ab, Db, Gb, d, g, c, f, bb, eb
        # Note: 'c' and 'a' are natural, but follow sharps ascending.

        sharp_tonics = ['C', 'G', 'D', 'A', 'E', 'B', 'F#', 'e', 'b', 'f#', 'c#', 'g#', 'd#', 'a']
        flat_tonics = ['F', 'Bb', 'Eb', 'Ab', 'Db', 'Gb', 'd', 'g', 'c', 'f', 'bb', 'eb']

        # Check if tonic is in sharp list (case insensitive)
        if tonic_lower in [x.lower() for x in sharp_tonics]:
            self.notes = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"]
        elif tonic_lower in [x.lower() for x in flat_tonics]:
            self.notes = ["C", "Db", "D", "Eb", "E", "F", "Gb", "G", "Ab", "A", "Bb", "B"]
        else:
            # Fallback based on presence of # or b
            if '#' in self.tonic:
                self.notes = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"]
            elif 'b' in self.tonic:
                self.notes = ["C", "Db", "D", "Eb", "E", "F", "Gb", "G", "Ab", "A", "Bb", "B"]
            else:
                self.notes = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"]

        # Normalize tonic to find index
        self.tonic_normalized = self._normalize_tonic()
        self.start_index = self.notes.index(self.tonic_normalized)

    def _normalize_tonic(self):
        t = self.tonic
        if t[0].islower():
            t = t[0].upper() + t[1:]
        # If still not in list, try to match base note
        if t not in self.notes:
            base = t[0].upper()
            accidental = t[1:] if len(t) > 1 else ''
            for note in self.notes:
                if note[0].upper() == base:
                    if len(note) > 1:
                        if note[1] == accidental:
                            return note
                    else:
                        if not accidental:
                            return note
        return t

    def chromatic(self):
        return self.notes[self.start_index:] + self.notes[:self.start_index]

    def interval(self, intervals):
        scale = self.chromatic()
        result = [scale[0]]
        current = 0

        for i in intervals:
            if i == 'm':
                step = 1
            elif i == 'M':
                step = 2
            elif i == 'A':
                step = 3
            else:
                raise ValueError(f"Unknown interval: {i}")

            current = (current + step) % 12
            result.append(scale[current])

        return result

import java.awt.Point;
import java.util.*;

class GoCounting {
    private final char[][] grid;
    private final int height;
    private final int width;

    GoCounting(String board) {
        String[] rows = board.split("\n");
        this.height = rows.length;
        this.width = height > 0 ? rows[0].length() : 0;
        this.grid = new char[height][width];
        for (int r = 0; r < height; r++) {
            String row = rows[r];
            for (int c = 0; c < width; c++) {
                this.grid[r][c] = (c < row.length()) ? row.charAt(c) : ' ';
            }
        }
    }

    private boolean inBounds(int x, int y) {
        return x >= 0 && x < width && y >= 0 && y < height;
    }

    private Player determineOwner(int startX, int startY) {
        if (!inBounds(startX, startY) || grid[startY][startX] != ' ') {
            return Player.NONE;
        }

        Set<Point> visited = new HashSet<>();
        Queue<Point> q = new ArrayDeque<>();
        q.add(new Point(startX, startY));
        visited.add(new Point(startX, startY));

        Set<Player> borderPlayers = new HashSet<>();
        int[] dx = {1, -1, 0, 0};
        int[] dy = {0, 0, 1, -1};

        while (!q.isEmpty()) {
            Point p = q.poll();
            for (int i = 0; i < 4; i++) {
                int nx = p.x + dx[i];
                int ny = p.y + dy[i];
                if (inBounds(nx, ny)) {
                    char cell = grid[ny][nx];
                    if (cell == ' ') {
                        Point np = new Point(nx, ny);
                        if (!visited.contains(np)) {
                            visited.add(np);
                            q.add(np);
                        }
                    } else if (cell == 'B') {
                        borderPlayers.add(Player.BLACK);
                    } else if (cell == 'W') {
                        borderPlayers.add(Player.WHITE);
                    }
                }
            }
        }

        if (borderPlayers.isEmpty()) return Player.NONE;
        if (borderPlayers.size() == 1) return borderPlayers.iterator().next();
        return Player.NONE;
    }

    private Set<Point> getConnectedEmpty(int startX, int startY) {
        Set<Point> result = new HashSet<>();
        if (!inBounds(startX, startY) || grid[startY][startX] != ' ') {
            return result;
        }

        Queue<Point> q = new ArrayDeque<>();
        q.add(new Point(startX, startY));
        result.add(new Point(startX, startY));

        int[] dx = {1, -1, 0, 0};
        int[] dy = {0, 0, 1, -1};
        Set<Point> visited = new HashSet<>();
        visited.add(new Point(startX, startY));

        while (!q.isEmpty()) {
            Point p = q.poll();
            for (int i = 0; i < 4; i++) {
                int nx = p.x + dx[i];
                int ny = p.y + dy[i];
                if (inBounds(nx, ny) && grid[ny][nx] == ' ') {
                    Point np = new Point(nx, ny);
                    if (!visited.contains(np)) {
                        visited.add(np);
                        result.add(np);
                        q.add(np);
                    }
                }
            }
        }
        return result;
    }

    Player getTerritoryOwner(int x, int y) {
        if (!inBounds(x, y)) throw new IllegalArgumentException("Invalid coordinate");
        if (grid[y][x] != ' ') return Player.NONE;
        return determineOwner(x, y);
    }

    Set<Point> getTerritory(int x, int y) {
        if (!inBounds(x, y)) throw new IllegalArgumentException("Invalid coordinate");
        if (grid[y][x] != ' ') return new HashSet<>();
        return getConnectedEmpty(x, y);
    }

    Map<Player, Set<Point>> getTerritories() {
        Map<Player, Set<Point>> territories = new HashMap<>();
        territories.put(Player.BLACK, new HashSet<>());
        territories.put(Player.WHITE, new HashSet<>());
        territories.put(Player.NONE, new HashSet<>());

        Set<Point> processed = new HashSet<>();
        int[] dx = {1, -1, 0, 0};
        int[] dy = {0, 0, 1, -1};

        for (int y = 0; y < height; y++) {
            for (int x = 0; x < width; x++) {
                if (grid[y][x] == ' ' && !processed.contains(new Point(x, y))) {
                    Set<Point> region = new HashSet<>();
                    Set<Player> neighbors = new HashSet<>();
                    Queue<Point> q = new ArrayDeque<>();
                    q.add(new Point(x, y));
                    processed.add(new Point(x, y));
                    region.add(new Point(x, y));

                    while (!q.isEmpty()) {
                        Point p = q.poll();
                        for (int i = 0; i < 4; i++) {
                            int nx = p.x + dx[i];
                            int ny = p.y + dy[i];
                            if (inBounds(nx, ny)) {
                                char c = grid[ny][nx];
                                if (c == ' ') {
                                    Point np = new Point(nx, ny);
                                    if (!processed.contains(np)) {
                                        processed.add(np);
                                        region.add(np);
                                        q.add(np);
                                    }
                                } else if (c == 'B') {
                                    neighbors.add(Player.BLACK);
                                } else if (c == 'W') {
                                    neighbors.add(Player.WHITE);
                                }
                            }
                        }
                    }

                    if (neighbors.size() == 1) {
                        territories.put(neighbors.iterator().next(), region);
                    } else {
                        territories.put(Player.NONE, region);
                    }
                }
            }
        }
        return territories;
    }
}

