use std::ptr::{self, NonNull};
use std::marker::PhantomData;

struct Node<T> {
    data: T,
    next: Option<NonNull<Node<T>>>,
    prev: Option<NonNull<Node<T>>>,
}

pub struct LinkedList<T> {
    head: Option<NonNull<Node<T>>>,
    tail: Option<NonNull<Node<T>>>,
    len: usize,
    _marker: PhantomData<T>,
}

pub struct Cursor<'a, T> {
    list: *mut LinkedList<T>,
    node: Option<NonNull<Node<T>>>,
    _marker: PhantomData<&'a mut T>,
}

pub struct Iter<'a, T> {
    current: Option<NonNull<Node<T>>>,
    _marker: PhantomData<&'a T>,
}

impl<T> LinkedList<T> {
    pub fn new() -> Self {
        LinkedList {
            head: None,
            tail: None,
            len: 0,
            _marker: PhantomData,
        }
    }

    pub fn is_empty(&self) -> bool {
        self.len == 0
    }

    pub fn len(&self) -> usize {
        self.len
    }

    pub fn cursor_front(&mut self) -> Cursor<'_, T> {
        Cursor {
            list: self as *mut LinkedList<T>,
            node: self.head,
            _marker: PhantomData,
        }
    }

    pub fn cursor_back(&mut self) -> Cursor<'_, T> {
        Cursor {
            list: self as *mut LinkedList<T>,
            node: self.tail,
            _marker: PhantomData,
        }
    }

    pub fn iter(&self) -> Iter<'_, T> {
        Iter {
            current: self.head,
            _marker: PhantomData,
        }
    }

    // Helper methods to be used by pre_implemented
    pub(crate) fn push_back(&mut self, value: T) {
        let mut cursor = self.cursor_back();
        cursor.insert_after(value);
    }

    pub(crate) fn push_front(&mut self, value: T) {
        let mut cursor = self.cursor_front();
        cursor.insert_before(value);
    }

    pub(crate) fn pop_back(&mut self) -> Option<T> {
        if self.tail.is_none() {
            return None;
        }
        let mut cursor = self.cursor_back();
        cursor.take()
    }

    pub(crate) fn pop_front(&mut self) -> Option<T> {
        if self.head.is_none() {
            return None;
        }
        let mut cursor = self.cursor_front();
        cursor.take()
    }
}

impl<T> Cursor<'_, T> {
    pub fn peek_mut(&mut self) -> Option<&mut T> {
        self.node.map(|node| unsafe { &mut (*node.as_ptr()).data })
    }

    pub fn next(&mut self) -> Option<&mut T> {
        let node = self.node?;
        unsafe {
            let next = (*node.as_ptr()).next?;
            self.node = Some(next);
            Some(&mut (*next.as_ptr()).data)
        }
    }

    pub fn prev(&mut self) -> Option<&mut T> {
        let node = self.node?;
        unsafe {
            let prev = (*node.as_ptr()).prev?;
            self.node = Some(prev);
            Some(&mut (*prev.as_ptr()).data)
        }
    }

    pub fn take(&mut self) -> Option<T> {
        let node = self.node?;
        unsafe {
            let list = &mut *self.list;
            let prev = (*node.as_ptr()).prev;
            let next = (*node.as_ptr()).next;

            if let Some(prev_node) = prev {
                (*prev_node.as_ptr()).next = next;
            } else {
                list.head = next;
            }

            if let Some(next_node) = next {
                (*next_node.as_ptr()).prev = prev;
            } else {
                list.tail = prev;
            }

            list.len -= 1;

            let node_ptr = node.as_ptr();
            let mut node_box = Box::from_raw(node_ptr);
            Some(ptr::read(&node_box.data))
        }
    }

    pub fn insert_after(&mut self, value: T) {
        let current = self.node;
        unsafe {
            let new_node = Box::into_raw(Box::new(Node {
                data: value,
                next: None,
                prev: None,
            }));
            let new_node_ptr = NonNull::new_unchecked(new_node);

            let next = if let Some(curr) = current {
                (*curr.as_ptr()).next
            } else {
                None
            };

            (*new_node_ptr.as_ptr()).next = next;
            (*new_node_ptr.as_ptr()).prev = current;

            if let Some(curr) = current {
                (*curr.as_ptr()).next = Some(new_node_ptr);
            } else {
                let list = &mut *self.list;
                list.head = Some(new_node_ptr);
            }

            if let Some(next_node) = next {
                (*next_node.as_ptr()).prev = Some(new_node_ptr);
            } else {
                let list = &mut *self.list;
                list.tail = Some(new_node_ptr);
            }

            let list = &mut *self.list;
            list.len += 1;
            self.node = Some(new_node_ptr);
        }
    }

    pub fn insert_before(&mut self, value: T) {
        let current = self.node;
        unsafe {
            let new_node = Box::into_raw(Box::new(Node {
                data: value,
                next: None,
                prev: None,
            }));
            let new_node_ptr = NonNull::new_unchecked(new_node);

            let prev = if let Some(curr) = current {
                (*curr.as_ptr()).prev
            } else {
                None
            };

            (*new_node_ptr.as_ptr()).next = current;
            (*new_node_ptr.as_ptr()).prev = prev;

            if let Some(curr) = current {
                (*curr.as_ptr()).prev = Some(new_node_ptr);
            } else {
                let list = &mut *self.list;
                list.tail = Some(new_node_ptr);
            }

            if let Some(prev_node) = prev {
                (*prev_node.as_ptr()).next = Some(new_node_ptr);
            } else {
                let list = &mut *self.list;
                list.head = Some(new_node_ptr);
            }

            let list = &mut *self.list;
            list.len += 1;
            self.node = Some(new_node_ptr);
        }
    }
}

impl<'a, T> Iterator for Iter<'a, T> {
    type Item = &'a T;

    fn next(&mut self) -> Option<Self::Item> {
        let current = self.current?;
        unsafe {
            let data = &(*current.as_ptr()).data;
            self.current = (*current.as_ptr()).next;
            Some(data)
        }
    }
}

impl<T> Drop for LinkedList<T> {
    fn drop(&mut self) {
        let mut current = self.head;
        while let Some(node) = current {
            unsafe {
                let next = (*node.as_ptr()).next;
                let _ = Box::from_raw(node.as_ptr());
                current = next;
            }
        }
        self.head = None;
        self.tail = None;
        self.len = 0;
    }
}

impl<T> Default for LinkedList<T> {
    fn default() -> Self {
        Self::new()
    }
}

impl<T> Clone for LinkedList<T>
where
    T: Clone,
{
    fn clone(&self) -> Self {
        let mut new_list = LinkedList::new();
        for item in self.iter() {
            new_list.push_back(item.clone());
        }
        new_list
    }
}

impl<T> PartialEq for LinkedList<T>
where
    T: PartialEq,
{
    fn eq(&self, other: &Self) -> bool {
        if self.len() != other.len() {
            return false;
        }
        let mut self_iter = self.iter();
        let mut other_iter = other.iter();
        loop {
            match (self_iter.next(), other_iter.next()) {
                (Some(a), Some(b)) => {
                    if a != b {
                        return false;
                    }
                }
                (None, None) => return true,
                _ => return false,
            }
        }
    }
}

impl<T> Eq for LinkedList<T> where T: Eq {}

unsafe impl<T> Send for LinkedList<T> {}
unsafe impl<T> Sync for LinkedList<T> {}

class School:
    def __init__(self):
        self._data = {}
        self._history = []

