    def added(self):
        return self._history

export class Forth {
  constructor() {
    this._stack = [];
    this.definitions = new Map();
  }

  get stack() {
    return [...this._stack];
  }

  evaluate(input) {
    const tokens = input.trim().split(/\s+/).filter(t => t.length > 0);
    const processedTokens = this.processTokens(tokens);

    for (const token of processedTokens) {
      if (this.isNumber(token)) {
        this._stack.push(parseInt(token, 10));
      } else {
        this.executeWord(token.toUpperCase());
      }
    }
  }

  isNumber(str) {
    return /^-?\d+$/.test(str);
  }

  processTokens(tokens) {
    const result = [];
    let i = 0;

    while (i < tokens.length) {
      const token = tokens[i].toUpperCase();

      if (token === ':') {
        i++;
        if (i >= tokens.length) throw new Error('Invalid definition');

        const wordName = tokens[i].toUpperCase();
        if (this.isNumber(wordName)) throw new Error('Invalid definition');

        i++;
        const definition = [];

        while (i < tokens.length && tokens[i].toUpperCase() !== ';') {
          definition.push(tokens[i].toUpperCase());
          i++;
        }

        if (i >= tokens.length) throw new Error('Invalid definition');

        // Validate and expand the definition
        const expandedDef = this.expandDefinition(definition);
        this.definitions.set(wordName, expandedDef);
        i++; // Skip the semicolon
      } else {
        result.push(token);
        i++;
      }
    }

    return result;
  }

  expandDefinition(definition) {
    return definition.map(word => {
      const upperWord = word.toUpperCase();
      if (this.definitions.has(upperWord)) {
        return this.definitions.get(upperWord);
      }
      return [upperWord];
    }).flat();
  }

  executeWord(word) {
    const upperWord = word.toUpperCase();

    if (this.definitions.has(upperWord)) {
      const definition = this.definitions.get(upperWord);
      for (const defWord of definition) {
        this.executeWord(defWord);
      }
      return;
    }

    switch (upperWord) {
      case '+':
        this.binaryOperation((a, b) => a + b);
        break;
      case '-':
        this.binaryOperation((a, b) => a - b);
        break;
      case '*':
        this.binaryOperation((a, b) => a * b);
        break;
      case '/':
        this.binaryOperation((a, b) => {
          if (b === 0) throw new Error('Division by zero');
          return Math.trunc(a / b);
        });
        break;
      case 'DUP':
        this.unaryOperation(() => {
          if (this._stack.length === 0) throw new Error('Stack empty');
          return this._stack[this._stack.length - 1];
        });
        break;
      case 'DROP':
        this.unaryOperation(() => {
          if (this._stack.length === 0) throw new Error('Stack empty');
          this._stack.pop();
          return null;
        });
        break;
      case 'SWAP':
        this.binaryOperation((a, b) => [b, a]);
        break;
      case 'OVER':
        this.binaryOperation((a, b) => [a, b, a]);
        break;
      default:
        throw new Error('Unknown word');
    }
  }

  binaryOperation(operation) {
    if (this._stack.length < 2) {
      if (this._stack.length === 0) throw new Error('Stack empty');
      throw new Error('Only one value on the stack');
    }

    const b = this._stack.pop();
    const a = this._stack.pop();

    const result = operation(a, b);

    if (Array.isArray(result)) {
      this._stack.push(...result);
    } else {
      this._stack.push(result);
    }
  }

  unaryOperation(operation) {
    const result = operation();
    if (result !== null) {
      this._stack.push(result);
    }
  }
}

def answer(question):
    if not question.startswith("What is ") or not question.endswith("?"):
        raise ValueError("syntax error")

    content = question[8:-1].strip()
    if not content:
        raise ValueError("syntax error")

    tokens = content.split()
    if not tokens:
        raise ValueError("syntax error")

    # Validate first token is a number
    try:
        result = int(tokens[0])
    except ValueError:
        raise ValueError("syntax error")

    i = 1
    while i < len(tokens):
        op = tokens[i]

        if op in ("plus", "minus"):
            if i + 1 >= len(tokens):
                raise ValueError("syntax error")
            try:
                val = int(tokens[i+1])
            except ValueError:
                raise ValueError("syntax error")

            if op == "plus":
                result += val
            else:
                result -= val
            i += 2

        elif op == "multiplied":
            if i + 3 >= len(tokens) or tokens[i+1] != "by":
                raise ValueError("syntax error")
            try:
                val = int(tokens[i+2])
            except ValueError:
                raise ValueError("syntax error")
            result *= val
            i += 3

        elif op == "divided":
            if i + 3 >= len(tokens) or tokens[i+1] != "by":
                raise ValueError("syntax error")
            try:
                val = int(tokens[i+2])
            except ValueError:
                raise ValueError("syntax error")
            result //= val
            i += 3

        else:
            raise ValueError("unknown operation")

    return result

import java.util.ArrayList;
import java.util.List;
import java.util.Random;
import java.util.Set;

public class MazeGenerator {

    public char[][] generatePerfectMaze(int rows, int columns) {
        return generatePerfectMaze(rows, columns, (int) (Math.random() * Integer.MAX_VALUE));
    }

    public char[][] generatePerfectMaze(int rows, int columns, int seed) {
        if (rows < 5 || rows > 100 || columns < 5 || columns > 100) {
            throw new IllegalArgumentException("Maze dimensions must be between 5 and 100.");
        }

        int height = rows * 2 + 1;
        int width = columns * 2 + 1;
        char[][] maze = new char[height][width];

        // Initialize with walls
        for (int i = 0; i < height; i++) {
            for (int j = 0; j < width; j++) {
                if (i % 2 == 0 || j % 2 == 0) {
                    maze[i][j] = ' ';
                } else {
                    maze[i][j] = ' ';
                }
            }
        }

        // Use a grid to track visited cells (only odd coordinates are cells)
        boolean[][] visited = new boolean[rows][columns];
        Random random = new Random(seed);

        // Start from (0,0)
        int startRow = 0;
        int startCol = 0;
        List<int[]> stack = new ArrayList<>();
        stack.add(new int[]{startRow, startCol});
        visited[startRow][startCol] = true;

        while (!stack.isEmpty()) {
            int[] current = stack.get(stack.size() - 1);
            int r = current[0];
            int c = current[1];

            // Find unvisited neighbors
            List<int[]> neighbors = new ArrayList<>();
            int[] dr = {-1, 1, 0, 0};
            int[] dc = {0, 0, -1, 1};

            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i];
                int nc = c + dc[i];
                if (nr >= 0 && nr < rows && nc >= 0 && nc < columns && !visited[nr][nc]) {
                    neighbors.add(new int[]{nr, nc});
                }
            }

            if (!neighbors.isEmpty()) {
                int[] next = neighbors.get(random.nextInt(neighbors.size()));
                int nr = next[0];
                int nc = next[1];

                // Remove wall between current and next
                if (nr == r + 1) {
                    maze[r * 2 + 2][c * 2 + 1] = ' ';
                } else if (nr == r - 1) {
                    maze[(r - 1) * 2 + 2][c * 2 + 1] = ' ';
                } else if (nc == c + 1) {
                    maze[r * 2 + 1][c * 2 + 2] = ' ';
                } else if (nc == c - 1) {
                    maze[r * 2 + 1][(c - 1) * 2 + 2] = ' ';
                }

                visited[nr][nc] = true;
                stack.add(new int[]{nr, nc});
            } else {
                stack.remove(stack.size() - 1);
            }
        }

        // Draw the outer walls and entrance/exit
        // We need to determine entrance and exit positions.
        // The problem implies a single entrance on the left and single exit on the right.
        // The examples show specific positions, but they vary.
        // Let's pick a random row for entrance and exit on the left and right walls.
        // The entrance is at column 0, exit at column width-1.
        // The row must be odd (cell row) to be an opening in the wall.
        // Rows 1, 3, 5, ... are cell rows.
        // We need to pick one row for entrance and one for exit.
        // To ensure it's a valid opening, we just pick a random odd row index.

        int entranceRow = 1 + 2 * random.nextInt(rows);
        int exitRow = 1 + 2 * random.nextInt(rows);

        // Fill the maze with walls first, then carve paths, then draw borders
        // Re-initialize to ensure clean state before drawing borders
        for (int i = 0; i < height; i++) {
            for (int j = 0; j < width; j++) {
                if (i % 2 == 0 && j % 2 == 0) {
                    // Corner or intersection
                    if (i == 0 && j == 0) {
                        maze[i][j] = '┌';
                    } else if (i == 0 && j == width - 1) {
                        maze[i][j] = '┐';
                    } else if (i == height - 1 && j == 0) {
                        maze[i][j] = '└';
                    } else if (i == height - 1 && j == width - 1) {
                        maze[i][j] = '┘';
                    } else {
                        maze[i][j] = '┼';
                    }
                } else if (i % 2 == 0) {
                    // Horizontal wall
                    if (i == 0) {
                        if (j == 1) {
                            // Check if this is the exit position? No, exit is on right wall.
                            // Exit is at column width-1.
                            // The exit is an opening in the right wall.
                            // The right wall is at column width-1.
                            // The opening is at row exitRow.
                            // So at (exitRow, width-1) we put '⇨'? No, '⇨' is inside the cell?
                            // Looking at example:
                            // Row 3 (index 3), col 10 (width 11).
                            // The character at (3, 10) is '⇨'.
                            // Wait, col 10 is the last column (width-1).
                            // So the exit is at (exitRow, width-1).
                            // But the wall is at width-1.
                            // So we replace the wall character with '⇨'.
                            // But wait, the example shows '⇨' at (3, 10).
                            // The wall at (3, 10) would be '│' if it's a vertical wall.
                            // But the right wall is vertical.
                            // So we replace the vertical wall character with '⇨'.
                            // Similarly for entrance at (entranceRow, 0).
                        }
                        maze[i][j] = '─';
                    } else if (i == height - 1) {
                        maze[i][j] = '─';
                    } else {
                        maze[i][j] = '─';
                    }
                } else if (j % 2 == 0) {
                    // Vertical wall
                    if (j == 0) {
                        if (i == entranceRow) {
                            maze[i][j] = '⇨';
                        } else {
                            maze[i][j] = '│';
                        }
                    } else if (j == width - 1) {
                        if (i == exitRow) {
                            maze[i][j] = '⇨';
                        } else {
                            maze[i][j] = '│';
                        }
                    } else {
                        maze[i][j] = '│';
                    }
                } else {
                    // Cell
                    maze[i][j] = ' ';
                }
            }
        }

        // Now we need to handle the corners and intersections correctly.
        // The previous loop might have overwritten corners with '─' or '│'.
        // Let's redo the border drawing more carefully.

        // Reset to a clean state for walls
        for (int i = 0; i < height; i++) {
            for (int j = 0; j < width; j++) {
                if (i % 2 == 0 && j % 2 == 0) {
                    // Corner or intersection
                    if (i == 0 && j == 0) {
                        maze[i][j] = '┌';
                    } else if (i == 0 && j == width - 1) {
                        maze[i][j] = '┐';
                    } else if (i == height - 1 && j == 0) {
                        maze[i][j] = '└';
                    } else if (i == height - 1 && j == width - 1) {
                        maze[i][j] = '┘';
                    } else {
                        maze[i][j] = '┼';
                    }
                } else if (i % 2 == 0) {
                    // Horizontal wall
                    maze[i][j] = '─';
                } else if (j % 2 == 0) {
                    // Vertical wall
                    maze[i][j] = '│';
                } else {
                    // Cell
                    maze[i][j] = ' ';
                }
            }
        }

        // Now place entrance and exit
        // Entrance at (entranceRow, 0)
        // Exit at (exitRow, width-1)
        // These are on the vertical walls (j=0 and j=width-1).
        // We replace the '│' with '⇨'.
        maze[entranceRow][0] = '⇨';
        maze[exitRow][width - 1] = '⇨';

        // Also, we need to make sure the entrance and exit are openings.
        // The wall at (entranceRow, 0) is '│'. We replaced it with '⇨'.
        // But we also need to ensure the cell next to it is open.
        // The cell at (entranceRow, 1) is already ' ' (open).
        // Similarly for exit.
        // The cell at (exitRow, width-2) is already ' '.

        // However, we need to check if the entrance/exit row is a valid cell row.
        // entranceRow and exitRow are odd, so they are cell rows.
        // The wall at (entranceRow, 0) is '│'. We replaced it with '⇨'.
        // This is correct.

        // But wait, the example shows the entrance at row 5 (index 5) for a 5x5 maze.
        // 5x5 maze has height 11. Rows 0..10.
        // Cell rows are 1, 3, 5, 7, 9.
        // So 5 is a valid cell row.
        // The exit is at row 3 (index 3).
        // So we just pick random odd rows.

        return maze;
    }
}

#include "bank_account.h"
#include <stdexcept>
#include <mutex>

namespace Bankaccount {

class Bankaccount {
public:
    Bankaccount() : balance_(0), is_open_(false) {}

    void open() {
        std::lock_guard<std::mutex> lock(mutex_);
        if (is_open_) {
            throw std::runtime_error("Account already open");
        }
        is_open_ = true;
        balance_ = 0;
    }

    void close() {
        std::lock_guard<std::mutex> lock(mutex_);
        if (!is_open_) {
            throw std::runtime_error("Account not open");
        }
        is_open_ = false;
    }

    int balance() const {
        std::lock_guard<std::mutex> lock(mutex_);
        if (!is_open_) {
            throw std::runtime_error("Account closed");
        }
        return balance_;
    }

    void deposit(int amount) {
        std::lock_guard<std::mutex> lock(mutex_);
        if (!is_open_) {
            throw std::runtime_error("Account closed");
        }
        if (amount < 0) {
            throw std::runtime_error("Cannot deposit negative amount");
        }
        balance_ += amount;
    }

    void withdraw(int amount) {
        std::lock_guard<std::mutex> lock(mutex_);
        if (!is_open_) {
            throw std::runtime_error("Account closed");
        }
        if (amount < 0) {
            throw std::runtime_error("Cannot withdraw negative amount");
        }
        if (amount > balance_) {
            throw std::runtime_error("Insufficient funds");
        }
        balance_ -= amount;
    }

private:
    mutable std::mutex mutex_;
    int balance_;
    bool is_open_;
};

}  // namespace Bankaccount

class Zipper:
    def __init__(self, focus, path):
        self.focus = focus
        self.path = path

    @staticmethod
    def from_tree(tree):
        return Zipper(tree, [])

    def value(self):
        return self.focus["value"]

    def set_value(self, value):
        new_focus = {**self.focus, "value": value}
        return Zipper(new_focus, self.path)

    def left(self):
        if self.focus.get("left") is None:
            return None
        new_path = [{"dir": "left", "parent": self.focus, "sibling": self.focus.get("right")}] + self.path
        return Zipper(self.focus["left"], new_path)

    def set_left(self, subtree):
        new_focus = {**self.focus, "left": subtree}
        return Zipper(new_focus, self.path)

    def right(self):
        if self.focus.get("right") is None:
            return None
        new_path = [{"dir": "right", "parent": self.focus, "sibling": self.focus.get("left")}] + self.path
        return Zipper(self.focus["right"], new_path)

    def set_right(self, subtree):
        new_focus = {**self.focus, "right": subtree}
        return Zipper(new_focus, self.path)

    def up(self):
        if not self.path:
            return None
        step = self.path[0]
        parent = {**step["parent"]}
        if step["dir"] == "left":
            parent["left"] = self.focus
        else:
            parent["right"] = self.focus
        return Zipper(parent, self.path[1:])

    def to_tree(self):
        current = self.focus
        for step in reversed(self.path):
            parent = {**step["parent"]}
            if step["dir"] == "left":
                parent["left"] = current
            else:
                parent["right"] = current
            current = parent
        return current

    def __eq__(self, other):
        if not isinstance(other, Zipper):
            return False
        return self.focus == other.focus and self.path == other.path

import java.util.ArrayList;
import java.util.Collection;

class CustomSet<T> {
    private ArrayList<T> data;

    CustomSet() {
        this.data = new ArrayList<>();
    }

    CustomSet(Collection<T> data) {
        this.data = new ArrayList<>();
        if (data != null) {
            for (T item : data) {
                boolean found = false;
                for (T existing : this.data) {
                    if (isEquivalent(existing, item)) {
                        found = true;
                        break;
                    }
                }
                if (!found) {
                    this.data.add(item);
                }
            }
        }
    }

    boolean isEmpty() {
        return data.isEmpty();
    }

    boolean contains(T element) {
        for (T item : data) {
            if (isEquivalent(item, element)) {
                return true;
            }
        }
        return false;
    }

    boolean isDisjoint(CustomSet<T> other) {
        for (T item : other.data) {
            if (this.contains(item)) {
                return false;
            }
        }
        return true;
    }

    boolean add(T element) {
        if (this.contains(element)) {
            return false;
        }
        data.add(element);
        return true;
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;
        CustomSet<?> other = (CustomSet<?>) obj;
        if (data.size() != other.data.size()) return false;
        for (T item : data) {
            boolean found = false;
            for (Object otherItem : other.data) {
                if (isEquivalent(item, (T) otherItem)) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                return false;
            }
        }
        return true;
    }

    CustomSet<T> getIntersection(CustomSet<T> other) {
        CustomSet<T> result = new CustomSet<>();
        for (T item : data) {
            if (other.contains(item)) {
                result.data.add(item);
            }
        }
        return result;
    }

    CustomSet<T> getUnion(CustomSet<T> other) {
        CustomSet<T> result = new CustomSet<>(this.data);
        for (T item : other.data) {
            if (!result.contains(item)) {
                result.data.add(item);
            }
        }
        return result;
    }

    CustomSet<T> getDifference(CustomSet<T> other) {
        CustomSet<T> result = new CustomSet<>();
        for (T item : data) {
            if (!other.contains(item)) {
                result.data.add(item);
            }
        }
        return result;
    }

    boolean isSubset(CustomSet<T> other) {
        for (T item : data) {
            if (!other.contains(item)) {
                return false;
            }
        }
        return true;
    }

    private boolean isEquivalent(T a, T b) {
        if (a == null) {
            return b == null;
        }
        return a.equals(b);
    }
}

import org.json.JSONArray;
import org.json.JSONObject;
import java.util.*;
import java.util.stream.Collectors;

public class RestApi {
    private final Map<String, User> users = new HashMap<>();

    public RestApi() {
    }

    public RestApi(User... users) {
        for (User user : users) {
            this.users.put(user.getName(), user);
        }
    }

    public String get(String url) {
        return get(url, null);
    }

    public String get(String url, JSONObject payload) {
        if ("/users".equals(url)) {
            JSONArray result = new JSONArray();
            if (payload == null) {
                for (User user : users.values()) {
                    result.put(user.toJson());
                }
            } else {
                JSONArray names = payload.getJSONArray("users");
                List<String> requestedNames = new ArrayList<>();
                for (int i = 0; i < names.length(); i++) {
                    requestedNames.add(names.getString(i));
                }
                List<User> filteredUsers = new ArrayList<>();
                for (String name : requestedNames) {
                    if (users.containsKey(name)) {
                        filteredUsers.add(users.get(name));
                    }
                }
                filteredUsers.sort(Comparator.comparing(User::getName));
                for (User user : filteredUsers) {
                    result.put(user.toJson());
                }
            }
            return new JSONObject().put("users", result).toString();
        }
        return new JSONObject().put("error", "Not found").toString();
    }

    public String post(String url, JSONObject payload) {
        if ("/add".equals(url)) {
            String name = payload.getString("user");
            if (users.containsKey(name)) {
                return users.get(name).toJson().toString();
            }
            User newUser = new User(name);
            users.put(name, newUser);
            return newUser.toJson().toString();
        } else if ("/iou".equals(url)) {
            String lenderName = payload.getString("lender");
            String borrowerName = payload.getString("borrower");
            double amount = payload.getDouble("amount");

            User lender = users.get(lenderName);
            User borrower = users.get(borrowerName);

            if (lender == null || borrower == null) {
                return new JSONObject().put("error", "User not found").toString();
            }

            lender.recordIou(borrowerName, amount, true);
            borrower.recordIou(lenderName, amount, false);

            List<User> resultUsers = new ArrayList<>();
            resultUsers.add(lender);
            resultUsers.add(borrower);
            resultUsers.sort(Comparator.comparing(User::getName));

            JSONArray result = new JSONArray();
            for (User user : resultUsers) {
                result.put(user.toJson());
            }
            return new JSONObject().put("users", result).toString();
        }
        return new JSONObject().put("error", "Not found").toString();
    }

    private static class User {
        private final String name;
        private final Map<String, Double> owes = new HashMap<>();
        private final Map<String, Double> owedBy = new HashMap<>();

        public User(String name) {
            this.name = name;
        }

        public String getName() {
            return name;
        }

        public void recordIou(String otherName, double amount, boolean isLender) {
            if (isLender) {
                if (owes.containsKey(otherName)) {
                    double existingOwe = owes.get(otherName);
                    if (existingOwe >= amount) {
                        double newOwe = existingOwe - amount;
                        if (newOwe == 0.0) {
                            owes.remove(otherName);
                        } else {
                            owes.put(otherName, newOwe);
                        }
                    } else {
                        owes.remove(otherName);
                        double newOwedBy = amount - existingOwe;
                        owedBy.put(otherName, newOwedBy);
                    }
                } else {
                    owedBy.put(otherName, owedBy.getOrDefault(otherName, 0.0) + amount);
                }
            } else {
                if (owedBy.containsKey(otherName)) {
                    double existingOwed = owedBy.get(otherName);
                    if (existingOwed >= amount) {
                        double newOwed = existingOwed - amount;
                        if (newOwed == 0.0) {
                            owedBy.remove(otherName);
                        } else {
                            owedBy.put(otherName, newOwed);
                        }
                    } else {
                        owedBy.remove(otherName);
                        double newOwes = amount - existingOwed;
                        owes.put(otherName, newOwes);
                    }
                } else {
                    owes.put(otherName, owes.getOrDefault(otherName, 0.0) + amount);
                }
            }
        }

        public JSONObject toJson() {
            JSONObject json = new JSONObject();
            json.put("name", name);

            JSONObject owesJson = new JSONObject();
            List<String> owesKeys = new ArrayList<>(owes.keySet());
            Collections.sort(owesKeys);
            for (String key : owesKeys) {
                owesJson.put(key, owes.get(key));
            }
            json.put("owes", owesJson);

            JSONObject owedByJson = new JSONObject();
            List<String> owedByKeys = new ArrayList<>(owedBy.keySet());
            Collections.sort(owedByKeys);
            for (String key : owedByKeys) {
                owedByJson.put(key, owedBy.get(key));
            }
            json.put("owedBy", owedByJson);

            double balance = calculateBalance();
            json.put("balance", balance);

            return json;
        }

        private double calculateBalance() {
            double totalOwedBy = owedBy.values().stream().mapToDouble(Double::doubleValue).sum();
            double totalOwes = owes.values().stream().mapToDouble(Double::doubleValue).sum();
            return totalOwedBy - totalOwes;
        }
    }
}

package transpose

func Transpose(input []string) []string {
	if len(input) == 0 {
		return []string{}
	}

	// Find the maximum length of any row
	maxLen := 0
	for _, row := range input {
		if len(row) > maxLen {
			maxLen = len(row)
		}
	}

	// Create a slice of strings for the result
	result := make([]string, maxLen)

	// Iterate over each column index
	for col := 0; col < maxLen; col++ {
		var sb []byte
		for row := 0; row < len(input); row++ {
			if col < len(input[row]) {
				sb = append(sb, input[row][col])
			} else {
				// Determine if we need to add a space
				// We add a space if there is any character in a subsequent row at this column or beyond
				shouldPad := false
				for k := row + 1; k < len(input); k++ {
					if col < len(input[k]) {
						shouldPad = true
						break
					}
				}
				if shouldPad {
					sb = append(sb, ' ')
				}
			}
		}
		result[col] = string(sb)
	}

	return result
}

use time::{Duration, PrimitiveDateTime as DateTime};

// Returns a DateTime one billion seconds after start.
pub fn after(start: DateTime) -> DateTime {
    let gigasecond = Duration::new(1_000_000_000, 0);
    start + gigasecond
}

pub fn encode(n: u64) -> String {
    if n == 0 {
        return "zero".to_string();
    }

    let ones = ["", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine",
                "ten", "eleven", "twelve", "thirteen", "fourteen", "fifteen", "sixteen",
                "seventeen", "eighteen", "nineteen"];
    let tens = ["", "", "twenty", "thirty", "forty", "fifty", "sixty", "seventy", "eighty", "ninety"];
    let scales = ["", " thousand", " million", " billion"];

    let mut result = String::new();
    let mut num = n;
    let mut scale_idx = 0;
    let mut first = true;

    while num > 0 {
        let chunk = (num % 1000) as u32;
        num /= 1000;

        if chunk > 0 {
            if !first {
                result.push(' ');
            }
            first = false;

            let hundreds = (chunk / 100) as usize;
            let remainder = chunk % 100;

            if hundreds > 0 {
                result.push_str(&ones[hundreds]);
                result.push_str(" hundred");
            }

            if remainder > 0 {
                if hundreds > 0 {
                    result.push(' ');
                }

                if remainder < 20 {
                    result.push_str(&ones[remainder as usize]);
                } else {
                    let ten_digit = (remainder / 10) as usize;
                    let one_digit = remainder % 10;

                    result.push_str(&tens[ten_digit]);
                    if one_digit > 0 {
                        result.push('-');
                        result.push_str(&ones[one_digit as usize]);
                    }
                }
            }

            result.push_str(scales[scale_idx]);
        }

        scale_idx += 1;
    }

    result
}

package foodchain

import (
	"fmt"
	"strings"
)

var animals = []string{"fly", "spider", "bird", "cat", "dog", "goat", "cow", "horse"}

var specialReactions = map[int]string{
	1: "It wriggled and jiggled and tickled inside her.",
	2: "How absurd to swallow a bird!",
	3: "Imagine that, to swallow a cat!",
	4: "What a hog, to swallow a dog!",
	5: "Just opened her throat and swallowed a goat!",
	6: "I don't know how she swallowed a cow!",
	7: "She's dead, of course!",
}

func Verse(v int) string {
	idx := v - 1
	var lines []string

	lines = append(lines, fmt.Sprintf("I know an old lady who swallowed a %s.", animals[idx]))

	if idx == 7 {
		lines = append(lines, specialReactions[idx])
		return strings.Join(lines, "\n")
	}

	if idx > 0 {
		lines = append(lines, specialReactions[idx])
	}

	for i := idx; i > 0; i-- {
		if i == 1 {
			lines = append(lines, fmt.Sprintf("She swallowed the %s to catch the %s that wriggled and jiggled and tickled inside her.", animals[i], animals[i-1]))
		} else {
			lines = append(lines, fmt.Sprintf("She swallowed the %s to catch the %s.", animals[i], animals[i-1]))
		}
	}

	lines = append(lines, "I don't know why she swallowed the fly. Perhaps she'll die.")
	return strings.Join(lines, "\n")
}

func Verses(start, end int) string {
	var result []string
	for i := start; i <= end; i++ {
		result = append(result, Verse(i))
	}
	return strings.Join(result, "\n\n")
}

func Song() string {
	return Verses(1, 8)
}

pub fn translate(input: &str) -> String {
    input
        .split_whitespace()
        .map(|w| {
            let chars: Vec<char> = w.chars().collect();
            let mut prefix_len = 0;
            let len = chars.len();

            while prefix_len < len {
                let c = chars[prefix_len];
                let is_vowel = matches!(c, 'a' | 'e' | 'i' | 'o' | 'u');

                // Rule 1: Starts with vowel
                if prefix_len == 0 && is_vowel {
                    break;
                }

                // Rule 1: Starts with "xr" or "yt"
                if prefix_len == 0 {
                    if c == 'x' && prefix_len + 1 < len && chars[prefix_len + 1] == 'r' {
                        break;
                    }
                    if c == 'y' && prefix_len + 1 < len && chars[prefix_len + 1] == 't' {
                        break;
                    }
                }

                // Rule 3: "qu" handling
                if c == 'q' && prefix_len + 1 < len && chars[prefix_len + 1] == 'u' {
                    prefix_len += 2;
                    continue;
                }

                // Rule 4: 'y' acts as vowel if preceded by consonants
                if c == 'y' && prefix_len > 0 {
                    break;
                }

                // If we hit a vowel (and it's not 'u' after 'q' which is handled above)
                if is_vowel {
                    break;
                }

                prefix_len += 1;
            }

            if prefix_len == len {
                format!("{}ay", w)
            } else {
                let (head, tail) = w.split_at(prefix_len);
                format!("{}{}ay", tail, head)
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

