package cryptosquare

import (
	"math"
	"strings"
	"unicode"
)

func Encode(pt string) string {
	if pt == "" {
		return ""
	}

	// Normalize: remove non-alphanumeric and lowercase
	var normalized strings.Builder
	for _, r := range pt {
		if unicode.IsLetter(r) || unicode.IsDigit(r) {
			normalized.WriteRune(unicode.ToLower(r))
		}
	}
	s := normalized.String()
	n := len(s)

	// Calculate dimensions
	c := int(math.Ceil(math.Sqrt(float64(n))))
	r := int(math.Ceil(float64(n) / float64(c)))
	if r*c < n {
		r++
	}
	// Ensure c >= r and c - r <= 1
	if c < r {
		c = r
	}
	if c-r > 1 {
		c = r
	}

	// Pad the string to fill the rectangle
	padded := make([]byte, r*c)
	copy(padded, s)
	for i := n; i < r*c; i++ {
		padded[i] = ' '
	}

	// Read columns
	var result strings.Builder
	for col := 0; col < c; col++ {
		if col > 0 {
			result.WriteByte(' ')
		}
		for row := 0; row < r; row++ {
			idx := row*c + col
			result.WriteByte(padded[idx])
		}
	}

	return result.String()
}
